diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 33b66aeaffe6..14f88d2845a0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2902,6 +2902,14 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return replaceInstUsesWith(CI, Fabs);
     }

+    // fabs (fadd X, 0.0) --> fabs (X)
+    // fabs (fadd 0.0, X) --> fabs (X)
+    Value *X2;
+    if (match(Arg, m_c_FAdd(m_AnyZeroFP(), m_Value(X2)))) {
+      CallInst *Fabs = Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X2, II);
+      return replaceInstUsesWith(CI, Fabs);
+    }
+
     if (match(Arg, m_Select(m_Value(Cond), m_Value(TVal), m_Value(FVal)))) {
       // fabs (select Cond, TrueC, FalseC) --> select Cond, AbsT, AbsF
       if (Arg->hasOneUse() ? (isa<Constant>(TVal) || isa<Constant>(FVal))

